using Ledgerly.Domain.Common; using Ledgerly.Domain.Enums; using Ledgerly.Domain.Exceptions; using Ledgerly.Domain.ValueObjects; namespace Ledgerly.Domain.Entities; public sealed class Expense:OrganizationScopedEntity{ public string Description{get;private set;}=string.Empty; public DateOnly ExpenseDate{get;private set;} public CurrencyCode Currency{get;private set;} public Guid ExpenseAccountId{get;private set;} public Guid PaymentAccountId{get;private set;} public Guid? VendorId{get;private set;} public Guid? TaxCodeId{get;private set;} public Money Amount{get;private set;} public Money TaxAmount{get;private set;} public Money TotalAmount{get;private set;} public string? ReceiptUrl{get;private set;} public ExpenseStatus Status{get;private set;} public Guid? JournalEntryId{get;private set;} private Expense(){Currency=new CurrencyCode("USD");Amount=TaxAmount=TotalAmount=new Money(0m,Currency);} public Expense(Guid organizationId,string description,DateOnly expenseDate,CurrencyCode currency,Guid expenseAccountId,Guid paymentAccountId,Money amount,Guid? vendorId,Guid? taxCodeId,string? receiptUrl):base(organizationId){ if(string.IsNullOrWhiteSpace(description))throw new DomainException("Description is required."); if(amount.Amount<=0m)throw new DomainException("Amount must be greater than zero."); Description=description.Trim(); ExpenseDate=expenseDate; Currency=currency; ExpenseAccountId=expenseAccountId; PaymentAccountId=paymentAccountId; Amount=amount; TaxAmount=new Money(0m,currency); TotalAmount=amount; VendorId=vendorId; TaxCodeId=taxCodeId; ReceiptUrl=string.IsNullOrWhiteSpace(receiptUrl)?null:receiptUrl.Trim(); Status=ExpenseStatus.Draft;} public void SetReceipt(string? receiptUrl){ if(Status!=ExpenseStatus.Draft)throw new DomainException("Receipt can only be updated for draft expenses."); ReceiptUrl=string.IsNullOrWhiteSpace(receiptUrl)?null:receiptUrl.Trim(); Touch();} public void Post(decimal taxRate){ if(Status!=ExpenseStatus.Draft)throw new DomainException("Expense is not in draft status."); TaxAmount=taxRate<=0m||!TaxCodeId.HasValue?new Money(0m,Currency):new Money(Math.Round(Amount.Amount*taxRate,2,MidpointRounding.AwayFromZero),Currency); TotalAmount=Amount+TaxAmount; Status=ExpenseStatus.Posted; Touch();}
public void Post(TaxCode? taxCode){ if(Status!=ExpenseStatus.Draft)throw new DomainException("Expense is not in draft status."); TaxAmount=taxCode is null||!TaxCodeId.HasValue?new Money(0m,Currency):new Money(taxCode.CalculateTaxAmount(Amount.Amount),Currency); TotalAmount=Amount+TaxAmount; Status=ExpenseStatus.Posted; Touch();} public void AttachJournalEntry(Guid journalEntryId){JournalEntryId=journalEntryId;Touch();} public void Void(){ if(Status!=ExpenseStatus.Posted)throw new DomainException("Only posted expenses can be voided."); Status=ExpenseStatus.Void; Touch();} }
